 47→const getRequestOrigin = (req) => {
 48→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 49→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 50→    const host = forwardedHost || req.get('host') || '';
 51→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 52→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 53→        ? forwardedProto
 54→        : requestProtocol === 'http' || requestProtocol === 'https'
 55→            ? requestProtocol
 56→            : 'https';
 57→
 58→    if (!host) {
 59→        return SITE_URL;
 60→    }
 61→
 62→    return `${protocol}://${host}`;
