101→const extractFromLexical = (contentJson) => {
102→    try {
103→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
104→        const texts = [];
105→        let firstImage = null;
106→
107→        const walk = (node) => {
108→            if (!node || typeof node !== 'object') return;
109→
110→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
111→            if (nodeType === 'text' && typeof node.text === 'string') {
112→                texts.push(node.text);
113→            }
114→
115→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
116→            if (!firstImage && isImageNode) {
117→                const image = imageFromNodeLike(node);
118→                if (image) {
119→                    firstImage = image;
120→                }
121→            }
122→
123→            if (Array.isArray(node.children)) {
124→                node.children.forEach(walk);
125→            }
126→        };
127→
128→        if (parsed?.root) {
129→            walk(parsed.root);
130→        }
131→
132→        return {
133→            text: normalizeWhitespace(texts.join(' ')),
134→            image: firstImage
135→        };
136→    } catch {
137→        return { text: '', image: null };
138→    }
139→};
