141→const extractFromCanvasDoc = (canvasDocRaw) => {
142→    try {
143→        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
144→        const text = Array.isArray(doc?.snippets)
145→            ? normalizeWhitespace(
146→                doc.snippets
147→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
148→                    .join(' ')
149→            )
150→            : '';
151→
152→        let image = null;
153→        if (Array.isArray(doc?.images)) {
154→            const first = doc.images.find((img) => imageFromNodeLike(img));
155→            if (first) image = imageFromNodeLike(first);
156→        }
157→
158→        return { text, image };
159→    } catch {
160→        return { text: '', image: null };
161→    }
162→};
