201→const resolveAbsoluteHttpUrl = (rawUrl) => {
202→    try {
203→        const raw = String(rawUrl || '').trim();
204→        if (!raw) return null;
205→
206→        const isSupabasePath =
207→            raw.startsWith('/storage/v1/object/public/')
208→            || raw.startsWith('storage/v1/object/public/');
209→
210→        const baseUrl = isSupabasePath && SUPABASE_URL
211→            ? `${SUPABASE_URL}/`
212→            : SITE_URL;
213→
214→        const parsed = new URL(raw, baseUrl);
215→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
216→            return null;
217→        }
218→        return parsed.toString();
219→    } catch {
220→        return null;
221→    }
