224→const isPrivateIpv4Address = (ip) => {
225→    const parts = ip.split('.').map((part) => Number(part));
226→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
227→        return true;
228→    }
229→
230→    const [a, b] = parts;
231→    if (a === 10 || a === 127 || a === 0) return true;
232→    if (a === 169 && b === 254) return true;
233→    if (a === 172 && b >= 16 && b <= 31) return true;
234→    if (a === 192 && b === 168) return true;
235→    return false;
236→};
