238→const isPrivateIpv6Address = (ip) => {
239→    const normalized = ip.toLowerCase();
240→    return (
241→        normalized === '::1' ||
242→        normalized.startsWith('fc') ||
243→        normalized.startsWith('fd') ||
244→        normalized.startsWith('fe80:')
245→    );
246→};
