248→const isPrivateIpAddress = (ip) => {
249→    const ipVersion = net.isIP(ip);
250→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
251→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
252→    return true;
253→};
