255→const isSafeRemoteImageUrl = (imageUrl) => {
256→    try {
257→        const parsed = new URL(imageUrl);
258→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
259→            return false;
260→        }
261→
262→        const hostname = parsed.hostname.toLowerCase();
263→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
264→            return false;
265→        }
266→
267→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
268→            return false;
269→        }
270→
271→        return true;
272→    } catch {
273→        return false;
274→    }
275→};
