277→const evaluateShareImageCandidate = (rawUrl) => {
278→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
279→    if (!absoluteUrl) {
280→        return {
281→            ok: false,
282→            reason: 'invalid_or_non_http_url',
283→            resolvedUrl: null,
284→        };
285→    }
286→
287→    let path = '';
288→    try {
289→        const parsed = new URL(absoluteUrl);
290→        path = String(parsed.pathname || '').toLowerCase();
291→    } catch {
292→        return {
293→            ok: false,
294→            reason: 'invalid_resolved_url',
295→            resolvedUrl: null,
296→        };
297→    }
298→
299→    if (path.endsWith('.svg')) {
300→        return {
301→            ok: false,
302→            reason: 'svg_not_supported_for_share_image',
303→            resolvedUrl: absoluteUrl,
304→        };
305→    }
306→
307→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
308→        return {
309→            ok: false,
310→            reason: 'unsafe_remote_url',
311→            resolvedUrl: absoluteUrl,
312→        };
313→    }
314→
315→    return {
316→        ok: true,
317→        reason: 'ok',
318→        resolvedUrl: absoluteUrl,
319→    };
320→};
