322→const fetchRemoteImageBuffer = async (imageUrl) => {
323→    const controller = new AbortController();
324→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
325→
326→    try {
327→        const response = await fetch(imageUrl, {
328→            method: 'GET',
329→            redirect: 'follow',
330→            signal: controller.signal,
331→            headers: {
332→                Accept: 'image/*,*/*;q=0.8',
333→                'Accept-Encoding': 'identity',
334→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
335→            },
336→        });
337→
338→        if (!response.ok) {
339→            throw new Error(`upstream image status ${response.status}`);
340→        }
341→
342→        const finalUrl = response.url || imageUrl;
343→        if (!isSafeRemoteImageUrl(finalUrl)) {
344→            throw new Error('upstream redirected to unsafe url');
345→        }
346→
347→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
348→        if (!contentType.startsWith('image/')) {
349→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
350→        }
351→        if (contentType.includes('image/svg')) {
352→            throw new Error('svg images are not used for share previews');
353→        }
354→
355→        const headerContentLength = Number(response.headers.get('content-length'));
356→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
357→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
358→        }
359→
360→        const arrayBuffer = await response.arrayBuffer();
361→        const buffer = Buffer.from(arrayBuffer);
362→
363→        if (!buffer.length) {
364→            throw new Error('upstream image is empty');
365→        }
366→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
367→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
368→        }
369→
370→        return {
371→            buffer,
372→            contentType,
373→            byteLength: buffer.length,
374→            finalUrl,
375→        };
376→    } finally {
377→        clearTimeout(timeout);
378→    }
379→};
