447→// ── Profile share route: composite OG image for social media ──
448→app.get('/share/u/:username/image', async (req, res) => {
449→    const { username } = req.params;
450→
451→    try {
452→        const result = await getUserByUsernameService(username);
453→        const user = result?.userData?.[0];
454→        if (!user) {
455→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
456→        }
457→
458→        const displayName = normalizeWhitespace(user.name) || username;
459→        const handle = `@${normalizeWhitespace(user.username || username)}`;
460→        const bio = toPreviewText(user.bio || '', 120);
461→
462→        // ── Fetch background image ──
463→        let bgBuffer = null;
464→        const bgStyle = user.background || {};
465→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
466→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
467→            : null;
468→        const bgImageUrl = bgImageMatch?.[1];
469→
470→        if (bgImageUrl) {
471→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
472→            if (bgEval.ok && bgEval.resolvedUrl) {
473→                try {
474→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
475→                    bgBuffer = remote.buffer;
476→                } catch { /* use fallback gradient */ }
477→            }
478→        }
479→
480→        // ── Base layer: background or dark gradient ──
481→        let baseLayer;
482→        if (bgBuffer) {
483→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
484→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
485→                .toBuffer();
486→        } else {
487→            // Dark gradient fallback
488→            const gradientSvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
489→                <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
490→                    <stop offset="0%" style="stop-color:#1a1a2e"/>
491→                    <stop offset="100%" style="stop-color:#16213e"/>
492→                </linearGradient></defs>
493→                <rect width="100%" height="100%" fill="url(#g)"/>
494→            </svg>`;
495→            baseLayer = await sharp(Buffer.from(gradientSvg))
496→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
497→                .png()
498→                .toBuffer();
499→        }
500→
501→        // ── Dark overlay for text readability ──
502→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
503→            <rect width="100%" height="100%" fill="rgba(0,0,0,0.55)"/>
504→        </svg>`;
505→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
506→
507→        // ── Circular avatar ──
508→        let avatarComposite = null;
509→        const avatarSize = 180;
510→        const avatarUrl = user.image_url;
511→        if (avatarUrl) {
512→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
513→            if (avatarEval.ok && avatarEval.resolvedUrl) {
514→                try {
515→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
516→                    const circleMask = Buffer.from(
517→                        `<svg width="${avatarSize}" height="${avatarSize}">
518→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
519→                        </svg>`
520→                    );
521→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
522→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
523→                        .png()
524→                        .toBuffer();
525→                    const circularAvatar = await sharp(resizedAvatar)
526→                        .composite([{ input: circleMask, blend: 'dest-in' }])
527→                        .png()
528→                        .toBuffer();
529→                    avatarComposite = circularAvatar;
530→                } catch { /* skip avatar */ }
531→            }
532→        }
533→
534→        // ── Text overlay SVG ──
535→        const textX = DEFAULT_OG_IMAGE_WIDTH / 2;
536→        const nameY = avatarComposite ? 340 : 240;
537→        const handleY = nameY + 40;
538→        const bioY = handleY + 45;
539→        const brandY = DEFAULT_OG_IMAGE_HEIGHT - 40;
540→
541→        const escapeSvg = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
542→
543→        const textSvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
544→            <style>
545→                .name { font-family: sans-serif; font-size: 48px; font-weight: 700; fill: #ffffff; }
546→                .handle { font-family: sans-serif; font-size: 28px; font-weight: 400; fill: rgba(255,255,255,0.7); }
547→                .bio { font-family: sans-serif; font-size: 24px; font-weight: 400; fill: rgba(255,255,255,0.85); }
548→                .brand { font-family: sans-serif; font-size: 22px; font-weight: 600; fill: rgba(255,255,255,0.5); }
549→            </style>
