553→            <text x="${textX}" y="${brandY}" text-anchor="middle" class="brand">iskrib.com</text>
554→        </svg>`;
555→        const textBuffer = await sharp(Buffer.from(textSvg)).png().toBuffer();
556→
557→        // ── Compose all layers ──
558→        const composites = [
559→            { input: overlayBuffer, top: 0, left: 0 },
560→        ];
561→
562→        if (avatarComposite) {
563→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
564→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
565→        }
566→
567→        composites.push({ input: textBuffer, top: 0, left: 0 });
568→
569→        const finalImage = await sharp(baseLayer)
570→            .composite(composites)
571→            .jpeg({ quality: 82, mozjpeg: true })
572→            .toBuffer();
573→
574→        res.set('Content-Type', 'image/jpeg');
575→        res.set('Cache-Control', 'public, max-age=3600');
576→        return res.send(finalImage);
577→    } catch (err) {
