645→app.get('/share/post/:journalId/image', async (req, res) => {
646→    const { journalId } = req.params;
647→    const debugMode = isShareImageDebugRequest(req);
648→    const debugPayload = {
649→        ok: false,
650→        fallback: false,
651→        journalId,
652→        stage: 'start',
653→        reason: '',
654→        meta: {
655→            imageCandidateSource: null,
656→            imageCandidateRaw: null,
657→            imageCandidateResolved: null,
658→            upstreamFinalUrl: null,
659→            upstreamContentType: null,
660→            upstreamBytes: null,
661→            outputBytes: null,
662→        },
663→    };
664→
665→    const fallbackWithReason = (reason) => {
666→        debugPayload.ok = false;
667→        debugPayload.fallback = true;
668→        debugPayload.stage = 'fallback';
669→        debugPayload.reason = reason;
670→        if (debugMode) {
671→            return sendShareImageDebug(res, debugPayload);
672→        }
673→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
674→    };
675→
676→    try {
677→        const journal = await getShareJournal(journalId);
678→        debugPayload.stage = 'journal_loaded';
679→        if (!journal) {
680→            return fallbackWithReason('journal_not_found');
681→        }
682→
683→        const shareMeta = buildShareMetaFromJournal(journal);
684→        debugPayload.stage = 'candidate_extracted';
685→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
686→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
687→
688→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
689→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
690→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
691→            return fallbackWithReason(candidateEvaluation.reason);
692→        }
693→
694→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
695→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
696→            return fallbackWithReason('candidate_is_default_fallback');
697→        }
698→
699→        debugPayload.stage = 'fetching_upstream';
700→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
701→        debugPayload.stage = 'upstream_loaded';
702→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
703→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
704→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
705→
706→        debugPayload.stage = 'converting_image';
707→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
708→        debugPayload.stage = 'converted_image';
709→        debugPayload.ok = true;
710→        debugPayload.reason = 'ok';
711→        debugPayload.meta.outputBytes = ogImageBuffer.length;
712→
713→        if (debugMode) {
714→            return sendShareImageDebug(res, debugPayload);
715→        }
716→
717→        res.set('Content-Type', 'image/jpeg');
718→        res.set('Cache-Control', 'public, max-age=3600');
719→        return res.send(ogImageBuffer);
720→    } catch (err) {
721→        debugPayload.stage = 'error';
722→        debugPayload.reason = err?.message || 'unknown_error';
723→        console.error('share image route error:', err?.message || err);
724→        return fallbackWithReason(debugPayload.reason);
725→    }
726→});
